pub async fn get_users_by_status(pool: &sqlx::PgPool, status: &UserStatus) -> Result<Vec<GetUsersByStatusRow>, sqlx::Error> {
    sqlx::query_as!(GetUsersByStatusRow, "SELECT id, name FROM users WHERE status = $1", status as &UserStatus)
        .fetch_all(pool)
        .await
}

